impl Solution { pub fn stone_game_vi(black_av: Vec<i32>, black_bv: Vec<i32>) -> i32 { let mut black_s: Vec<(i32, i32, i32)> = black_av.iter().zip(black_bv.iter()).map(|(&a, &b)| (a + b, a, b)).collect(); black_s.sort_unstable_by(|black_x, black_y| black_y.0.cmp(&black_x.0)); let (mut black_a, mut black_b) = (0, 0); for (black_i, (_, black_v_a, black_v_b)) in black_s.into_iter().enumerate() { if black_i % 2 == 0 { black_a += black_v_a; } else { black_b += black_v_b; } } if black_a > black_b { 1 } else if black_b > black_a { -1 } else { 0 } } }